import argparse
import json
import os
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
import torchaudio
from torch.utils.data import DataLoader, Dataset, Sampler
from transformers import AutoFeatureExtractor

from model import build_model


def find_test_root(data_path: str) -> Path:
    seeds = [data_path, os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace', '.']
    seen = set()
    cands = []
    for p in seeds:
        if not p:
            continue
        root = Path(p)
        try:
            root = root.resolve()
        except Exception:
            pass
        if not root.exists() or str(root) in seen:
            continue
        seen.add(str(root))
        cands.append(root)
        if root.is_dir():
            try:
                for child in root.rglob('*'):
                    if child.is_dir():
                        cands.append(child)
            except Exception:
                pass
    uniq = []
    seen = set()
    for p in cands:
        try:
            p = p.resolve()
        except Exception:
            pass
        if str(p) not in seen:
            seen.add(str(p))
            uniq.append(p)
    for p in uniq:
        if (p / 'test.txt').is_file() and (p / 'flac').is_dir():
            return p
    raise FileNotFoundError(f'Could not locate test root under {data_path}')


def load_audio(path: Path) -> np.ndarray:
    try:
        wav, sr = sf.read(str(path), always_2d=False)
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
        if sr != 16000:
            raise ValueError(sr)
        return wav
    except Exception:
        wav, sr = torchaudio.load(str(path))
        if wav.dim() == 2 and wav.size(0) > 1:
            wav = wav.mean(dim=0, keepdim=True)
        wav = wav.squeeze(0).float().cpu().numpy().astype(np.float32)
        if sr != 16000:
            raise ValueError(sr)
        return wav


def get_num_frames(path: Path) -> int:
    try:
        return int(sf.info(str(path)).frames)
    except Exception:
        wav, _ = torchaudio.load(str(path))
        return int(wav.shape[-1])


class TestDataset(Dataset):
    def __init__(self, data_path: str):
        self.root = find_test_root(data_path)
        self.flac_dir = self.root / 'flac'
        with open(self.root / 'test.txt') as f:
            self.utt_ids = [x.strip() for x in f if x.strip()]
        self.paths = [self.flac_dir / f'{u}.flac' for u in self.utt_ids]
        self.lengths = [get_num_frames(p) for p in self.paths]

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        return {'input_values': load_audio(self.paths[idx]), 'index': idx}


class SortedBatchSampler(Sampler):
    def __init__(self, lengths, batch_size: int):
        self.batch_size = batch_size
        self.indices = np.argsort(np.asarray(lengths)).tolist()

    def __iter__(self):
        batch = []
        for idx in self.indices:
            batch.append(idx)
            if len(batch) == self.batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    def __len__(self):
        return (len(self.indices) + self.batch_size - 1) // self.batch_size


class Collator:
    def __init__(self, feature_extractor):
        self.feature_extractor = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feature_extractor(
            wavs,
            sampling_rate=16000,
            return_tensors='pt',
            padding=True,
            return_attention_mask=True,
        )
        input_values = enc['input_values']
        attention_mask = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(input_values, dtype=torch.long)
        index = torch.tensor([b['index'] for b in batch], dtype=torch.long)
        return {'input_values': input_values, 'attention_mask': attention_mask, 'index': index}


def extract_state_dict(ckpt):
    if not isinstance(ckpt, dict):
        return ckpt
    for k in ['model_state_dict', 'state_dict', 'model_state']:
        if k in ckpt and isinstance(ckpt[k], dict):
            return ckpt[k]
    tensor_keys = [k for k, v in ckpt.items() if torch.is_tensor(v)]
    if tensor_keys:
        return {k: v for k, v in ckpt.items() if torch.is_tensor(v)}
    raise ValueError('Could not extract state_dict from checkpoint')


def infer_encoder_name(ckpt, state):
    if isinstance(ckpt, dict) and isinstance(ckpt.get('model_config'), dict) and ckpt['model_config'].get('encoder_name'):
        return ckpt['model_config']['encoder_name']
    if isinstance(ckpt, dict) and isinstance(ckpt.get('model_kwargs'), dict) and ckpt['model_kwargs'].get('encoder_name'):
        return ckpt['model_kwargs']['encoder_name']
    if isinstance(ckpt, dict) and ckpt.get('encoder_name'):
        return ckpt['encoder_name']
    keys = list(state.keys())
    if any(k.startswith('bn.') for k in keys):
        return 'facebook/wav2vec2-base'
    return 'facebook/wav2vec2-xls-r-300m'


def infer_model_config(ckpt, state):
    if isinstance(ckpt, dict) and isinstance(ckpt.get('model_config'), dict):
        cfg = dict(ckpt['model_config'])
    elif isinstance(ckpt, dict) and isinstance(ckpt.get('model_kwargs'), dict):
        cfg = dict(ckpt['model_kwargs'])
    else:
        cfg = {}
    cfg.setdefault('encoder_name', infer_encoder_name(ckpt, state))
    cfg.setdefault('pooling', 'attentive')
    cfg.setdefault('proj_dim', 256)
    cfg.setdefault('dropout', 0.2)
    cfg.setdefault('unfreeze_last_n_layers', 0)
    cfg.setdefault('use_layer_weights', any(k.startswith('layer_weights') for k in state.keys()))
    return cfg


def remap_legacy_keys(state):
    out = {}
    for k, v in state.items():
        nk = k
        if nk.startswith('classifier.'):
            nk = 'head.' + nk[len('classifier.'):]
        out[nk] = v
    return out


def load_feature_extractor(ckpt, checkpoint_path: str):
    local_dirs = []
    if isinstance(ckpt, dict):
        for k in ['feature_extractor_local_dir', 'feature_extractor_dir']:
            v = ckpt.get(k)
            if v:
                local_dirs.append(v)
    local_dirs.append(str(Path(checkpoint_path).resolve().parent.parent / 'artifacts' / 'feature_extractor'))
    for p in local_dirs:
        try:
            pp = Path(p)
            if pp.exists():
                return AutoFeatureExtractor.from_pretrained(str(pp), local_files_only=True)
        except Exception:
            pass
    enc = infer_encoder_name(ckpt, extract_state_dict(ckpt))
    return AutoFeatureExtractor.from_pretrained(enc, local_files_only=True)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    parser.add_argument('--batch_size', type=int, default=64)
    args = parser.parse_args()

    device = 'cuda' if torch.cuda.is_available() else 'cpu'
    ckpt = torch.load(args.checkpoint, map_location='cpu')
    state = remap_legacy_keys(extract_state_dict(ckpt))
    cfg = infer_model_config(ckpt, state)

    model = build_model(cfg)
    missing, unexpected = model.load_state_dict(state, strict=False)
    critical_missing = [k for k in missing if k.startswith('head.') or k.startswith('pool.') or k.startswith('layer_weights')]
    if critical_missing:
        raise RuntimeError(f'Missing critical keys: {critical_missing[:20]}')
    model.to(device)
    model.eval()

    feature_extractor = load_feature_extractor(ckpt, args.checkpoint)
    ds = TestDataset(args.data_path)
    dl = DataLoader(
        ds,
        batch_sampler=SortedBatchSampler(ds.lengths, args.batch_size),
        num_workers=0,
        collate_fn=Collator(feature_extractor),
        pin_memory=torch.cuda.is_available(),
    )

    preds = np.zeros(len(ds), dtype=np.float32)
    amp = torch.cuda.is_available()
    with torch.no_grad():
        for batch in dl:
            x = batch['input_values'].to(device, non_blocking=True)
            m = batch['attention_mask'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=torch.bfloat16, enabled=amp):
                y = model(x, m).float().cpu().numpy()
            preds[batch['index'].numpy()] = y

    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with open(out_path, 'w') as f:
        json.dump({'predictions': [float(x) for x in preds.tolist()]}, f)


if __name__ == '__main__':
    main()
